  ('public-health-specialist-moex-00706', 'public-health-specialist', 'public-health-specialist-moex-111-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '關於臺灣地區飲用水砷暴露以及其健康效應，下列敘述何者錯誤？', '["水體中含過量砷濃度之問題，不僅發生於臺灣，於世界其他地區，例如歐盟、外蒙古、中國、 印度、孟加拉、美國等，也曾有類似之報導", "砷暴露與缺血性心臟病、糖尿病以及高血壓有關", "曾經於臺灣西南沿岸地區發生之烏腳病事件，其居民主要是長期飲用淺水井（深度4～12米） 所造成，反之飲用深水井（深度120～180米）之居民，其不良健康效應之風險則較低", "砷暴露除了與皮膚癌有正向相關之外，臺灣地區之研究也發現砷暴露也與膀胱癌、腎臟癌、肺 癌以及肝癌風險增加有關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "8b85c2c136a5", "answer_pdf_sha1": "e31ea6bd6976", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
